import com.google.mlkit.vision.common.InputImage
import com.google.mlkit.vision.text.TextRecognition
import com.google.mlkit.vision.text.latin.TextRecognizerOptions
import android.graphics.Bitmap
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlin.coroutines.resume
import kotlin.coroutines.resumeWithException

data class OcrResult(
    val fullText: String,
    val blocks: List<String>   // one string per TextBlock
)

class OcrClient {
    private val recognizer = TextRecognition.getClient(TextRecognizerOptions.DEFAULT_OPTIONS)

    suspend fun recognizeText(bitmap: Bitmap): OcrResult =
        suspendCancellableCoroutine { cont ->
            val image = InputImage.fromBitmap(bitmap, 0)
            recognizer.process(image)
                .addOnSuccessListener { visionText ->
                    val blocks = visionText.textBlocks.map { block ->
                        block.lines.joinToString(" ") { it.text }
                    }
                    cont.resume(OcrResult(
                        fullText = visionText.text,
                        blocks = blocks
                    ))
                }
                .addOnFailureListener { cont.resumeWithException(it) }
        }
}

import com.google.mlkit.vision.objects.ObjectDetection
import com.google.mlkit.vision.objects.defaults.ObjectDetectorOptions

data class DetectedObject(
    val trackingId: Int?,
    val labels: List<Pair<String, Float>>,   // label to confidence
    val boundingBox: String                   // "(left,top)-(right,bottom)" for the prompt
)

class ObjectDetectorClient {
    private val options = ObjectDetectorOptions.Builder()
        .setDetectorMode(ObjectDetectorOptions.SINGLE_IMAGE_MODE)
        .enableClassification()
        .enableMultipleObjects()
        .build()

    private val detector = ObjectDetection.getClient(options)

    suspend fun detect(bitmap: Bitmap): List<DetectedObject> =
        suspendCancellableCoroutine { cont ->
            val image = InputImage.fromBitmap(bitmap, 0)
            detector.process(image)
                .addOnSuccessListener { detectedObjects ->
                    val results = detectedObjects.map { obj ->
                        val box = obj.boundingBox
                        DetectedObject(
                            trackingId = obj.trackingId,
                            labels = obj.labels.map { it.text to it.confidence },
                            boundingBox = "(${box.left},${box.top})-(${box.right},${box.bottom})"
                        )
                    }
                    cont.resume(results)
                }
                .addOnFailureListener { cont.resumeWithException(it) }
        }
}

sealed interface VisionContext {
    data class OcrContext(val result: OcrResult, val userQuestion: String) : VisionContext
    data class ObjectContext(val objects: List<DetectedObject>, val userQuestion: String) : VisionContext
}

object PromptAssembler {
    fun build(context: VisionContext): String = when (context) {
        is VisionContext.OcrContext -> """
            The following text was extracted from an image via OCR.
            Respond only based on the extracted text — do not invent additional content.

            EXTRACTED TEXT:
            ${context.result.fullText.trimIndent()}

            USER QUESTION: ${context.userQuestion}
        """.trimIndent()

        is VisionContext.ObjectContext -> {
            val objectList = context.objects.mapIndexed { i, obj ->
                val topLabel = obj.labels.maxByOrNull { it.second }
                "  ${i+1}. ${topLabel?.first ?: "unknown"} " +
                "(confidence: ${"%.0f".format((topLabel?.second ?: 0f) * 100)}%) " +
                "at ${obj.boundingBox}"
            }.joinToString("\n")

            """
                The following objects were detected in an image by an on-device model.
                Respond only based on the detected objects — do not invent additional content.

                DETECTED OBJECTS:
                $objectList

                USER QUESTION: ${context.userQuestion}
            """.trimIndent()
        }
    }
}

import android.graphics.Bitmap
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

sealed interface VisionPipelineState {
    object Idle                                      : VisionPipelineState
    object RunningMlKit                              : VisionPipelineState
    object AssemblingPrompt                          : VisionPipelineState
    data class StreamingReasoning(
        val accumulated: String,
        val isComplete: Boolean = false
    )                                                : VisionPipelineState
    data class Error(val message: String)            : VisionPipelineState
}

class VisionPipelineViewModel(
    private val ocrClient: OcrClient,
    private val objectDetector: ObjectDetectorClient,
    private val proxyClient: ClaudeProxyClient,
    private val sessionToken: String
) : ViewModel() {

    private val _state = MutableStateFlow<VisionPipelineState>(VisionPipelineState.Idle)
    val state: StateFlow<VisionPipelineState> = _state.asStateFlow()

    fun analyzeWithOcr(bitmap: Bitmap, userQuestion: String) {
        viewModelScope.launch {
            try {
                _state.value = VisionPipelineState.RunningMlKit
                val ocrResult = ocrClient.recognizeText(bitmap)

                _state.value = VisionPipelineState.AssemblingPrompt
                val prompt = PromptAssembler.build(
                    VisionContext.OcrContext(ocrResult, userQuestion)
                )

                streamToUi(prompt)
            } catch (e: Exception) {
                _state.value = VisionPipelineState.Error(e.message ?: "OCR failed")
            }
        }
    }

    fun analyzeWithObjectDetection(bitmap: Bitmap, userQuestion: String) {
        viewModelScope.launch {
            try {
                _state.value = VisionPipelineState.RunningMlKit
                val objects = objectDetector.detect(bitmap)

                _state.value = VisionPipelineState.AssemblingPrompt
                val prompt = PromptAssembler.build(
                    VisionContext.ObjectContext(objects, userQuestion)
                )

                streamToUi(prompt)
            } catch (e: Exception) {
                _state.value = VisionPipelineState.Error(e.message ?: "Detection failed")
            }
        }
    }

    private suspend fun streamToUi(prompt: String) {
        val request = ProxyRequest(
            query = prompt,
            sessionToken = sessionToken,
            routingReason = "vision-pipeline"
        )
        var accumulated = ""
        proxyClient.streamQuery(request).collect { delta ->
            accumulated += delta
            _state.value = VisionPipelineState.StreamingReasoning(accumulated)
        }
        _state.value = VisionPipelineState.StreamingReasoning(
            accumulated, isComplete = true
        )
    }
}

import com.google.mlkit.vision.label.ImageLabeling
import com.google.mlkit.vision.label.defaults.ImageLabelerOptions

class ImageLabelClient(confidenceThreshold: Float = 0.75f) {
    private val labeler = ImageLabeling.getClient(
        ImageLabelerOptions.Builder()
            .setConfidenceThreshold(confidenceThreshold)
            .build()
    )

    suspend fun label(bitmap: Bitmap): List<Pair<String, Float>> =
        suspendCancellableCoroutine { cont ->
            val image = InputImage.fromBitmap(bitmap, 0)
            labeler.process(image)
                .addOnSuccessListener { labels ->
                    cont.resume(labels.map { it.text to it.confidence })
                }
                .addOnFailureListener { cont.resumeWithException(it) }
        }
}

// Build a Claude prompt for alt-text generation
fun buildAltTextPrompt(labels: List<Pair<String, Float>>): String {
    val topLabels = labels.take(5).joinToString(", ") { (text, conf) ->
        "$text (${ "%.0f".format(conf * 100) }%)"
    }
    return """
        An image was analyzed by an on-device model and produced these category labels:
        $topLabels

        Write a single concise sentence (under 20 words) describing what the image
        likely shows. Use plain language suitable for a screen reader.
        Do not mention confidence percentages.
    """.trimIndent()
}

@Composable
fun VisionPipelineScreen(viewModel: VisionPipelineViewModel) {
    val state by viewModel.state.collectAsState()

    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        // Image area (bounding box overlay handled by a Canvas layer)
        Box(modifier = Modifier.fillMaxWidth().height(280.dp).background(Color.Black)) {
            // ... image + overlay rendering
        }

        Spacer(modifier = Modifier.height(12.dp))

        when (val s = state) {
            is VisionPipelineState.Idle -> {
                Text("Tap the camera button to scan an image", style = MaterialTheme.typography.bodyMedium)
            }
            is VisionPipelineState.RunningMlKit -> {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    CircularProgressIndicator(modifier = Modifier.size(16.dp), strokeWidth = 2.dp)
                    Spacer(modifier = Modifier.width(8.dp))
                    Text("Analyzing image on-device...")
                }
            }
            is VisionPipelineState.AssemblingPrompt -> {
                Text("Sending to Claude...")
            }
            is VisionPipelineState.StreamingReasoning -> {
                Card(modifier = Modifier.fillMaxWidth()) {
                    Column(modifier = Modifier.padding(12.dp)) {
                        Text(
                            text = s.accumulated + if (!s.isComplete) "▌" else "",
                            style = MaterialTheme.typography.bodyMedium
                        )
                    }
                }
            }
            is VisionPipelineState.Error -> {
                Text("Error: ${s.message}", color = MaterialTheme.colorScheme.error)
            }
        }
    }
}

